/**
 * Devuelve el SVG inline para un nombre de tag, probando primero match directo
 * y despues normalizando. Si no hay icono, devuelve undefined.
 */
export function getTagIcon(name: string): string | undefined {
  if (!name) return undefined;
  return TAG_ICONS[name] ?? TAG_ICONS[normalizeTagName(name)];
}
